mapper.sql:
from aiw_ai_skill s
where 1 = 1

    and s.skill_code = #{criteria.skillCode}


    and s.skill_type = #{criteria.skillType}


    and s.status = #{criteria.status}


    and (s.skill_code like concat('%', #{criteria.keyword}, '%')
         or s.skill_name like concat('%', #{criteria.keyword}, '%')
         or s.description like concat('%', #{criteria.keyword}, '%'))

mapper.select:
select *
from aiw_ai_skill
where skill_code = #{skillCode}
  and skill_version = #{skillVersion}

select s.* 
order by ${sortColumn}

    asc
    desc

limit #{offset}, #{criteria.size}
